import React, { useState, useEffect } from "react";
import axios from "axios";
import { FaHome, FaCog, FaBars, FaTimes } from "react-icons/fa";
import "./home.css";

function Home() {
  const userId = localStorage.getItem("userId"); // Récupérer l'ID de l'utilisateur connecté
  const apiUrl = `http://localhost:500/users/${userId}`;

  const [user, setUser] = useState({
    name: "",
    email: "",
    role: "",
    profilePicture: "",
    coverPhoto: "",
  });

  const [showModal, setShowModal] = useState(false);
  const [editName, setEditName] = useState("");
  const [editEmail, setEditEmail] = useState("");
  const [isOpen, setIsOpen] = useState(true);

  // Récupérer les données utilisateur depuis l'API
  useEffect(() => {
    if (userId) {
      axios
        .get(apiUrl)
        .then((response) => {
          setUser(response.data);
          setEditName(response.data.name);
          setEditEmail(response.data.email);
        })
        .catch((error) => console.error("Erreur lors de la récupération des données utilisateur :", error));
    }
  }, [userId, apiUrl]);

  // Fonction pour afficher/masquer la sidebar
  const toggleSidebar = () => setIsOpen(!isOpen);

  // Mise à jour du profil utilisateur
  const handleEdit = () => {
    axios
      .put(apiUrl, { name: editName, email: editEmail })
      .then((response) => {
        setUser(response.data);
        setShowModal(false);
      })
      .catch((error) => console.error("Erreur lors de la mise à jour du profil :", error));
  };

  // Suppression du compte
  const handleDelete = () => {
    if (window.confirm("Êtes-vous sûr de vouloir supprimer votre compte ?")) {
      axios
        .delete(apiUrl)
        .then(() => {
          localStorage.clear();
          alert("Votre compte a été supprimé !");
          setUser({ name: "", email: "", role: "", profilePicture: "", coverPhoto: "" });
        })
        .catch((error) => console.error("Erreur lors de la suppression du compte :", error));
    }
  };

  return (
    <div className="home-container">
      {/* Sidebar */}
      <div className={`sidebar ${isOpen ? "open" : "closed"}`}>
        <button className="toggle-btn" onClick={toggleSidebar}>
          {isOpen ? <FaTimes /> : <FaBars />}
        </button>
        <ul>
          <li>
            <FaHome /> {isOpen && <span>Home</span>}
          </li>
          <li>
            <FaCog /> {isOpen && <span>Settings</span>}
          </li>
        </ul>
      </div>

      {/* Main Content */}
      <div className="main-content">
        <div className="profile-header">
          <img src={user.coverPhoto || "https://via.placeholder.com/800x300"} alt="Couverture" className="cover-photo" />
          <img src={user.profilePicture || "https://via.placeholder.com/150"} alt="Profil" className="profile-picture" />
          <div className="info-section">
            <h2>{user.name || "Nom inconnu"}</h2>
            <p>Email: {user.email || "Non renseigné"}</p>
            <p>Rôle: {user.role || "Non défini"}</p>
          </div>
        </div>

        {/* Boutons d'action */}
        <div className="action-buttons">
          <button onClick={() => setShowModal(true)}>Modifier le profil</button>
          <button onClick={handleDelete}>Supprimer mon compte</button>
        </div>

        {/* Modal d'édition */}
        {showModal && (
          <div className="modal-overlay">
            <div className="modal">
              <h2>Modifier le profil</h2>
              <div className="modal-field">
                <label>Nom :</label>
                <input type="text" value={editName} onChange={(e) => setEditName(e.target.value)} />
              </div>
              <div className="modal-field">
                <label>Email :</label>
                <input type="email" value={editEmail} onChange={(e) => setEditEmail(e.target.value)} />
              </div>
              <div className="modal-actions">
                <button onClick={handleEdit}>Sauvegarder</button>
                <button onClick={() => setShowModal(false)}>Annuler</button>
              </div>
            </div>
          </div>
        )}
      </div>
    </div>
  );
}

export default Home;
